mapper.select:
SELECT ms.id, ms.material_code, ms.material_name, ms.category_level1_id, c1.category_name AS category_level1_name, c1.category_code AS category_level1_code, ms.category_level2_id, c2.category_name AS category_level2_name, c2.category_code AS category_level2_code, ms.category_level3_id, c3.category_name AS category_level3_name, c3.category_code AS category_level3_code, ms.spec_id, spec.spec_name, spec.spec_code, ms.unit_id, unit.unit_name, unit.unit_code, ms.remark, ms.status, ms.create_time, ms.update_time FROM material_standard ms LEFT JOIN material_category c1 ON ms.category_level1_id = c1.id LEFT JOIN material_category c2 ON ms.category_level2_id = c2.id LEFT JOIN material_category c3 ON ms.category_level3_id = c3.id LEFT JOIN material_specification spec ON ms.spec_id = spec.id LEFT JOIN material_unit unit ON ms.unit_id = unit.id WHERE ms.del_flag = '0'
AND ms.id = #{id}
AND ms.material_code LIKE CONCAT('%', #{materialCode}, '%')
AND ms.material_name LIKE CONCAT('%', #{materialName}, '%')
AND ms.category_level1_id = #{categoryLevel1Id}
AND ms.category_level2_id = #{categoryLevel2Id}
AND ms.category_level3_id = #{categoryLevel3Id}
AND ms.spec_id = #{specId}
AND ms.unit_id = #{unitId}
AND ms.status = #{status}
ORDER BY ms.create_time DESC
